public void delete()
{
    next delete();

    if((this.JournalType == ProdJournalType::Picklist || this.JournalType == ProdJournalType::ReportFinished) && ETGcanadaparameters::find().EnableDeleteValidations && this.ETGParentEntityJournalNumber)
    {
        ProdJournalTable prodJournaltable;
        ProdTable prodTable = ProdTable::find(this.ProdId);

        changecompany(prodTable.ETGParentEntity)
        {
            ttsbegin;
            select firstonly prodJournaltable
                where prodJournaltable.JournalId == this.ETGParentEntityJournalNumber
                && prodJournaltable.Posted == NoYes::No;

            if(prodJournaltable)
            {
                ttsbegin;
                prodJournaltable.selectForUpdate(true);
                prodJournaltable.delete();
                ttscommit;
            }
            ttscommit;
        }
    }
}
